INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Sân Pickleball CĐ Nguyễn Văn Trỗi', '66 Lâm Nhĩ, Hoà An, An Khê, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Hoà An, An Khe', 16.052017, 108.179169, 4.6, 9, '+84 828 647 205', 'https://www.google.com/maps/place/S%C3%A2n+Pickleball+C%C4%90+Nguy%E1%BB%85n+V%C4%83n+Tr%E1%BB%97i/data=!4m7!3m6!1s0x314219001a60815d:0x10a00d8099dd69ad!8m2!3d16.0520171!4d108.1791692!16s%2Fg%2F11x60089kd!19sChIJXYFgGgAZQjERrWndmYANoBA?authuser=0&hl=en&rclk=1', NULL, 'ChIJXYFgGgAZQjERrWndmYANoBA', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAFCoWQitkr8pkgVlcZMvFKHWoDBUHQQbaI4xXg4it7Hr6AeggGRqkePhUOv8R9BVu2U3TGuefy7s79NicX0Xs4XBJSyV29_iSQHi8GGJRBLwIvaHD1ykWI-rxNVQRiupcrG7kjX7Q=w408-h544-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFCoWQitkr8pkgVlcZMvFKHWoDBUHQQbaI4xXg4it7Hr6AeggGRqkePhUOv8R9BVu2U3TGuefy7s79NicX0Xs4XBJSyV29_iSQHi8GGJRBLwIvaHD1ykWI-rxNVQRiupcrG7kjX7Q=w224-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGHuazp6e-KOePWKHHzWArbAc3Feb1Y6X8F388Wuc_IjlT7FRiNC0BO_gyizk3Wybfo37FIr6C4BUQIXGV1VcCvnuN7XN9eqQVsKRIEFjp2ZmlR1LaWoliwuNMmRntygs6ZpJyG4Q=w529-h298-k-no"}]'::jsonb, '{}'::jsonb, '[{"Name": "Thien Dinh", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXrcd4QXpTu4HdVacAoqWLuETm7BHh6IbGYE_NOS6YupJ5EP0JZ=s120-c-rp-mo-br100", "Rating": 1, "Description": "Mình đã chơi cầu lông tại đây\nVề chất lượng sân: sân bê tông, nên có khả năng chấn thương cao và dễ hỏng vợt.\nVề không gian: thoáng, rộng, mát\nVề giá: giá niêm yết và giá thu KHÔNG thống nhất. Giá niêm yết 50k 1h cầu lông. Mình chơi từ 17:30-19:30 nhưng chủ và bác quản lý sân thu 130k/h (mình đã hỏi lại chủ nhưng anh cũng confirm là “giờ vàng” nên giá thế). Chênh lệch khá nhiều so với các sân trong phố.\n\nĐiều này khiến mình có trải nghiệm không tốt ngay lần đầu. Mọi người nên hỏi rõ về giá trước khi đặt.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1N_zJp8HpXVP6NgE2j5aHp0GqmjMMSYbl4jSWnyoOWC79i5o1UIo8T8CqKTLABKr9JTICxaFmJd6G13dWvULF8hPDeTX0s1YKaGQgzUwcDCKh4oFH8RTUTBVh98IEYdUgTdW8v=k-no"], "When": "2025-4-22"}, {"Name": "Ng Anh Duong", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWzuTIVrqf_VxDQYhRkuXggYFETkj7d7PbQGcN0EEZESHm-jCGQ=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "sân ruột, anh chủ dễ thương, hỗ trợ nhiệt tình", "Images": null, "When": ""}, {"Name": "Gia Viễn Ngô", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIttAHQtzdMNK7qkDxbelZnWoQAYry2GG7cr_2neEN7vZoMEA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Mặt sân đẹp, cảm giác thoáng đãng, có thể chơi trời mưa và nắng mà không cảm giác bị bí", "Images": null, "When": ""}, {"Name": "Đình bản Phan", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocI7X9gYzt_JTtF6JEBaR3_JKy5ugopo4ldBkU886DeExrHB7g=s120-c-rp-mo-br100", "Rating": 5, "Description": "Trải nghiệm tốt quán thoáng mát sân mới đẹp và chất lượng", "Images": null, "When": ""}, {"Name": "Coffee Thens", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUmftoXXJyzQLGtwPfVLdoVQMdNgZ16JGCvoV7a4Jd2BbNXIyc=s120-c-rp-mo-br100", "Rating": 5, "Description": "sân tốt, không gian thoáng đãng và thoải mái", "Images": null, "When": ""}, {"Name": "duyen duong", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJ81N7rgklLJeovv1FXGqf5SU5BCMxvoshIsdRbIscq0BODlA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân đẹp rộng thoáng mát, rất ok", "Images": null, "When": ""}, {"Name": "Cu Dinh Viet", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocL4eUod5dfpGw9F-pqu_0bhCOylX92VHaK7ueIkb2eKFbCBwg=s120-c-rp-mo-br100", "Rating": 5, "Description": "Trải nghiệm tuyệt vời cùng những người bạn", "Images": null, "When": ""}, {"Name": "bnhaaorn", "