, '[{"Name": "Tâm Nguyễn", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXZswPambGA9VKAFkD3mqiQf5YHa0LWH3QoMZSGYM2-QrYB5GA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Địa điểm vui chơi cho giới trẻ đam mê luyện tập nhưng không quá quan trọng luật chơi. Vui mà vẫn giảm cân được ai mà không thích nhỉ?", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2b-cy69JD-OGK-6AdfJvEzIsgeECQL6JXcqBxtXKbwpCObPPRFhBBP-kQ_UOrsL4TN5FywrrX3vhFDOGEEFycg-fQRTRcPi_9SKZF71PKRMevkS0O3zyhDk-DTIAd2M-Ewk7b5=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1mBigF7OmnnEutj9JSXpmLwUIA7gwMv7VSAvSbqOWXw_j3uMDW6755s4rWCU4G_hs3Xdu75Cu7RHXAvpZ7MqVgLAggjXhebcpKrO9Qw8by23JvLAZFYuqJGkrVK8OJ_O0PFdum=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn264IL5z3zbD7jtykxfClTZKHRsSRVQ476CHlp1NIxVGK09pqBh3XtEIy9SdsucKyfOafCbcFo1pc63kTxo6ABCoVaxter4INAFvUsGbHoIt7A-sf77aW_pa1JJ9MVg5ViKKNgm=k-no"], "When": "2024-9-2"}, {"Name": "Thế Viên Hà", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjX7L2VcPmTlcWIIZ1Dq4hku9herXtqfOBtZjtmZZl6GrnJYw57v=s120-c-rp-mo-ba3-br100", "Rating": 4, "Description": "Điểm cộng: sân trong nhà nên không lo nắng mưa, đậu xe thoải mái, nhân viên vui vẻ.\nĐiểm trừ: sân trơn làm bóng chạm sân lướt nhanh hơn, mặt sân dốc về phía đường. Không có lưới ngăn cách 2 sân, khi sân bên cạnh tập thì bóng tập bay qua mình khá nhiều. Giá vé hơi cao, tháng 11 có rất nhiều sân khai trương, chủ sân nên cân nhắc giá vé cạnh tranh.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0NiNdYjRoUyvMqZmDKfQ8MpwbiamWjRRQH8vgAj90XEqDILoytF7Oo3PD_noyrPjniKWHu4OTDzLO3uSOpl8Nke40hcKQXsKTErqOxQyzyKWFCdErrYBM2sZcZixYvuKpRf5hV=k-no"], "When": "2024-10-24"}, {"Name": "Bao Phan", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLqdCVAXW95dfc4yap6es8MbWpa_OfhZjtFS_iF4kGXBVQGiA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân trong nhà thoáng mát. Khỏi lo ướt chi trời mưa. Giá rẻ !!!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2krOa190TElj420qG1KZBzLQRTrc30QDxMHh3uoW6J8nFckBwZorTJxjQhBs1YUT6a1_cjESUlOvDYvb7rwOQ0hMG3HxxGamOmh4_U5LG-rPtIITY_II1qMDcM23mKTdXOGwA=k-no"], "When": "2024-7-14"}, {"Name": "Lam_nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKblWS1tHSRwEUAWkM4G2qUQd1xAZYxbWr593zFO5_MLKzvrQ=s120-c-rp-mo-br100", "Rating": 1, "Description": "Mặt sân bê tông không phẳng, không chuẩn, dễ trượt té do quá trơn. Đánh lâu dài sẽ ảnh hưởng đến khả năng phán đoán đường bóng. Giá vé cao so với mặt bằng chung ( 120k giờ thường và 150k giờ cao điểm).", "Images": null, "When": ""}, {"Name": "hoang lam", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIbOZEtCOxPj4tmgJvopz7nuzYHIHWTLT2vGo8GhqzD-G97jw=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Phù hợp mọi lứa tuổi. Dễ chơi dễ ghiền", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3DahhSZxQa7qV_ifDSNFOCQJUJWCMuipkV7DjizrQCFG4uBEgvCYUpws5PiUmR-6-H-EEhHxYNGpVTkDcsb0rUnhek1uxzILeDY02Y3gAf5evQ7DtWurv40NCvIbVuRgqkJtA0=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn09iMJAmFMRLcnTQ6xtMZQvs380qaaa0rTU4sM-BjHhevuDwmc8kFs-vguuoBltgsXy_NGIA1bwxYGQ1tpav2TirrQzZfL-QaXIb0xkhMaRnMItBOZBmNB9rlIW4ZJYWWGekHdKXw=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1ZiV1gCZje-iQSp9OnWtW0Nai7BZ3a-HWudqZqsyr9mJ1MK9UIWBiKe0_Y0J3C0gCGAVlpy4Rh_GDRaI_zguaMJNvQb9OlaoRdEHFIqE8Uh1EE8tMldCoRzMKXEPil-LJ8R16D=k-no"], "When": "2024-7-14"}, {"Name": "Thọ Huỳnh", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUidEOwfS_gNmitBSr6TzpYJTkC1wQdE8qO47233FPkyiebAtg=s120-c-rp-mo-br100", "Rating": 5, "Description": "nv vui vẻ, nhiệt tình, hỗ trợ hết mình cho các bạn mới chơi..👍👍👍", "Images": null, "When": ""}, {"Name": "Laij Nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVWb0_ArRC49Aw1pmi16T9mGYDg5ZhaL3Bj0ZuHyQiSwWh2tyHK=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Rất ổn", "Images": null, "When": ""}, {"Name": "tai duc", "ProfilePicture": "https://lh3.googleuserc