INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Sân pickleball Nam Hòa Xuân', '4 Đồng Khoa, Hoà Quý, Ngũ Hành Sơn, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Hoà Quý, Ngu Hanh Son', 15.999555, 108.243589, 5.0, 1, NULL, 'https://www.google.com/maps/place/S%C3%A2n+pickleball+Nam+H%C3%B2a+Xu%C3%A2n/data=!4m7!3m6!1s0x314211005f2534c3:0x8a0da1435deba4d6!8m2!3d15.9995552!4d108.2435891!16s%2Fg%2F11nhc6xzqp!19sChIJwzQlXwARQjER1qTrXUOhDYo?authuser=0&hl=en&rclk=1', NULL, 'ChIJwzQlXwARQjER1qTrXUOhDYo', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAEdC221syTCpH5cp7D2izHClfTLZ57t5Sxy6xkwKN7lHgkHNTAWHgxyIlh8F1ziEd9EkdSw0nN7WrUu-isY8FwbSmHdpvt46gU1A5dmXrzQx0_dq-GuineuephPVwvzF8hXVU2JDt-rnGhJ=w408-h725-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEdC221syTCpH5cp7D2izHClfTLZ57t5Sxy6xkwKN7lHgkHNTAWHgxyIlh8F1ziEd9EkdSw0nN7WrUu-isY8FwbSmHdpvt46gU1A5dmXrzQx0_dq-GuineuephPVwvzF8hXVU2JDt-rnGhJ=w224-h398-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAHvYTePvtIpk0epw07uVkwVa1YTCSYvbhtQTpeoXXV6WiyXvov_wVW8gUzn0ETNIVBPPSARxLfoi3rniHekKDhGFvg0hcENmaerbqn2mm-W5wol0jmFNavWOAPbZjt_1FDm2fEg3XV7axE=w529-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGJotX9wga-WqS3It6cW53VZ-0QQjOkNw_Pztl6JyXeRq_66VKTnbbmn_tZmwMAotZQkWUjNUspCKOOztIQZ_v-hSYstztGY21x3JyBQIEbAxENsO82UfxEMCJMiTTVDEEDTdoDQZOKVRto=w224-h398-k-no"}]'::jsonb, '{}'::jsonb, '[{"Name": "Thiên Ngô Bảo", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXKB2L_6vct9l7T3bXiiEbEcIe5a5GOw-jM68vuq7onM5y_C2t4=s120-c-rp-mo-ba7-br100", "Rating": 5, "Description": "Sân Pickleball Nam Hòa Xuân là điểm chơi mới khá ấn tượng tại khu vực Hòa Xuân, Đà Nẵng. Qua hình ảnh thực tế, sân có không gian rộng, thoáng, hệ thống chiếu sáng ban đêm mạnh và rõ, phù hợp cho những buổi đánh tối sau giờ làm. Mặt sân sạch sẽ, kẻ line chuẩn, cảm giác di chuyển ổn định và an toàn cho người chơi ở nhiều trình độ. Khu vực ghế ngồi xem bên ngoài khá thoải mái, thuận tiện cho người thân hoặc nhóm bạn ngồi cổ vũ.\nĐiểm nổi bật là cụm sân được đầu tư quy mô, xung quanh thoáng đãng nên không bị bí, tạo cảm giác chơi rất dễ chịu. Nếu hoàn thiện thêm các tiện ích như căn tin, khu thay đồ, gửi xe và cộng đồng hội nhóm mạnh thì đây sẽ là địa điểm rất tiềm năng của pickleball Hòa Xuân.\nMột sân mới, đẹp, sáng đèn, không khí sôi động và đáng trải nghiệm cho anh em đam mê pickleball tại Đà Nẵng. Hy vọng thời gian tới nơi đây sẽ trở thành điểm hẹn quen thuộc của cộng đồng thể thao khu Nam thành phố.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0AuU4H5tJBj67yeRE7RiS_wvpKlyXGePp-p1jjWm3Tm2umUguuk3yyXFxLIZlfh0Hzthy8uz13Yi4pAKMbxs5fnArdR-gx4uinUVq6tcsVxM06_ESzcpRSu9TuhYI1Z5vUgiXynm8kZbE=k-no"], "When": "2026-4-19"}]'::jsonb, '{}'::jsonb, NULL, ARRAY['Pickleball court'], NULL, NULL, NULL) ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
