INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('G4 Pickleball', '8 Đường số 2, An Hải, Đà Nẵng 550000, Vietnam', 'Da Nang', 'An Hải, An Hai', 16.079604, 108.236018, 4.5, 48, '+84 913 404 601', 'https://www.google.com/maps/place/G4+Pickleball/data=!4m7!3m6!1s0x314219001dcfa6ad:0xbe3ed8b9c6a8759!8m2!3d16.0796044!4d108.2360178!16s%2Fg%2F11wq77lqrn!19sChIJrabPHQAZQjERWYdqnIvt4ws?authuser=0&hl=en&rclk=1', NULL, 'ChIJrabPHQAZQjERWYdqnIvt4ws', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAEjOHXIDKz18lPXUIcvW0Gf5GOKI_vK70tpK_2kQpiheqnLnMYkO6jA5Lj789crCUH6Bt9fpVpF1HPJOS9kWLjTm9N0BatoN5oUFE0pTH42PNVyBX10TCxV4jJHdtoY3zPZBR7mz9UEz6Ic=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEjOHXIDKz18lPXUIcvW0Gf5GOKI_vK70tpK_2kQpiheqnLnMYkO6jA5Lj789crCUH6Bt9fpVpF1HPJOS9kWLjTm9N0BatoN5oUFE0pTH42PNVyBX10TCxV4jJHdtoY3zPZBR7mz9UEz6Ic=w397-h298-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAHDl5v3Jb6tpVy1PynhRmSmFyshuvnC4atHU9P6u_zeZcP-1h6V_pYyg8DycAbOV2eyFhacbUFnAoSYrkGcw6nR1c7l7BWPR_yqr104wuyeHl5k1BpC3SBTFFcFtONXdhC_jaVTYkso95Mo=w646-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFM1pJ6_FFDo4l9idoacelnYZ5D1STJbTlCdVn4wvPFAKSb5uJyUu3-EZ69NXCQObmRD4S4AXacZxW0PTmkEnedqsbbZIlOhPzh5a_42CxOHbDTXt1IJzDxyIiM9trRJ5P8kk0vGs5pRs5U=w224-h398-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=II1412PyOOmrQl6NVqtafA&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=353.26895&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Honest Evaluator", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWRTHjeBNz0rJxFJvTbab2HJqAOR1IbWS6aCHnECxlIsO4mMD8=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Easy to book.\nVery responsive.\nGreat space. Nice lighting.\nWell ventilated.", "Images": null, "When": ""}, {"Name": "Ka Ian Tin", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWWM3vtUYpjAsECFApFMDJgbp6iTJiI_rrW7KWvmnvv250XgFOA=s120-c-rp-mo-ba2-br100", "Rating": 1, "Description": "The staff is making the mistake many times. Confirmed booking one night before and when they saw no one coming at the time, they release the court to other customers without checking with me in any messages. And asked me to change time and change court, very bad customer service and handling. Not acceptable and not recommended to buy their package.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1ClZHUZum2es06uKZlqcunplrsqAMNBLiMtuxaPlyXQuB_sh6fbeArx8HEK5IlM8EVXPGYl9mp-jTMSsWFJtPeyAEk5nySZb0MP3OKRlmB_KiNIDxPWGnR9mbH-jrWJVTfQfW2tO4cAew=k-no"], "When": "2025-10-23"}, {"Name": "David", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXi7Sv6YZITfuoWtrXEQoGzkPKS9sIvkwnkrw5ygJfpO6mLO0NQ=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Great place to play Pickleball. The courts are really large and well laid out with dividers between each Court. The staff are super nice and they do have cold refreshments.", "Images": null, "When": ""}, {"Name": "Minh Phan", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIZE2DEwpacTskRSI8aS3wfyeMU6I-OQdPaj3ZVUnQDvSO1Dw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "I was lucky to find an open court on a walk-in. We had fun learning and enjoying the sport. Staff were super friendly and helpful.", "Images": null, "When": ""}, {"Name": "Gina Lannin", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXpamFfQmJaEmjfAgn8HZstTpElEXQrdzVsOope0TTP78D-WzI=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "I enjoy playing at G4.  The lighting is good, it has high ceilings to not interfere with lobs, and barriers between courts minimize loose balls.  They have cold drinks available for sale.   Many groups use G4 and you can sign up for social play on the Reclub app.  I don''t know how to book courts for your own group. Most courts have a fan,  but it does heat up in the hotter months.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0IVonSPvaFXeel_wms68gLewv2CFBjj__LxxigocFcjM8JDKsqnD77o6U2X4o8b0VpZhWoXastx2qYlAh9PR5TtYUw71NDVxtO1gVzJDg2S8MnPnWpHIupec8rsw2dZCFYbEwDFgy2MgCj=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0kRtEDDODynblPbKqEsfGGJtXqMR3669mfhxztqAVxV0FL4ZoTCrhtUx719RUDlXGfx3GWzI6tgyUYUyhayb446o5mmn6WfFsDa461014-VhXrpcB_YxmwH-0_IOXP-e_3ifsYWSgylsTG=k-no"], "When": "2026-3-30"}, {"Name": "Da Nang Yachts Charter", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXsRy2EfqBZhlBDswtMm-ydD7Xnx62BxXwayxCesMAlEZLvgsk=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "play all weekend with friends", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2C4yR4ePIqyMl5JwODvnMr81b1R7arp4m-edwt1lBDkmKK6E_F_V-1-0nmBHYCjc37zBWuUQWMahls4jRcp0xU3PjZDyuOq84XkMisVskZTqyygJq79nA3dPkvIwL7zucP1WIokgYynegO=k-no"], "When": "2026-3-15"}, {"Name": "Eat and travel", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWkLXv2WDzeA_d_DXObA_BwabbFxFnL8jnVLiOucvqdhyWGDGzY=s120-c-rp-mo-ba8-br100", "Rating": 5, "Description": "⭐️⭐️⭐️⭐️⭐️\n不過5星級嘅場地\n好寬敞的地方，好多個場地，但必須要提前預約，否則沒有機會打波\n\n我們就是沒有預約，企圖與當地人打友誼比賽，但是都沒機會，因為大家都有好波友打波\n\n正當準備放棄時候，老細告訴我們，有一個場地的客人沒有來，我們可以打波了，真的好開心\n\n當地人非常友善，我們還主動和旁邊場地的人打友誼賽", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2efpxwZbCmM7jukcDYb0A4yroDdcULYZnM5TfMjWhh7WSmDfcbvVFpy1vJHPaszoAczFzrWF6GYsllX52nEqlr6zPkaKZrylyujuLB1EFE6jXKAB6P3SSykQ0VgX3AvUosK-zNJqNz4Kt-=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0qvjtwlYPp0gzIR-WHQ4ing4c4CxZ8bHpfBE3dUj4ocrQCIe1T0AKfXUuHhRlJ_clUbJHRfZRSLhRlzkL2E3km78vV5gAVND-EQ9JP9gcitWDbauxr3kAP_OBq5yXbjTVwvb2RmXL98RV1=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3yPQXm-Kn8fu-TGSyc9fvlsoT2QanWrqh345BrxNrCQaXI0PLXRDAuJm8ZE-NSAYC7Zi76kWBZH6C9d6bNEtXZC3BYxuIAxeB_uSuoZEwPHqL1dbm82uIYTIuhpuF6Vkz_RhCIbF4JwnJK=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn22McmcQBkmi0rarrWklIKbnqrJTZuDcLzBhLqCec1p6_YC8qSj4IcFrDDfyhpAFrroxSyzeWnvZstljwzECw5xEATcjAVKt5dZo_QBrNaxJKeZ3H6zmHuCfSBd6yH0-HZMHR9ZqkJMMP6f=k-no"], "When": "2025-9-29"}, {"Name": "mArIn Life with Beach", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWL3UeYx-rJeURQHCX6vKLxLrFUObWZs32ZkPOY4jg92GXC7Bf_=s120-c-rp-mo-ba6-br100", "Rating": 5, "Description": "屋根があるため、天候に関係なく遊べるピックルボールコートです。\n\nコート数が多く、コートの料金も高くないため、使い勝手が良いのも特徴です。\n\n空気の換気機能が弱く、プレイし始めるとサウナのような環境になるため、水分はこまめに取りましょう（笑）\n\n扇風機とイスは各コートにあり、売店にはドリンクに加えアイスも売っているので、休みたい時に休める環境は整っています。\n\nありがとうございました！また行きます🏓🎾", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn27CT5aAauBcvB7ENPAGtYN66ci5Wab0kpYf8elIYR7S1g01MLUtgOALy9Qn-a6jZMxsoAn4yiCfAYTEvXOTQUDkuBXAVv-KhZA-v_zjFQswyF2xiloe_MMvMuFBUHJFV-fqT7Kg_DFFbuS=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1MFi5x9fbs2to6_Zm4wKLPYKpN2c8kdPylPQ64t9SFz4XGDVKKTxt61giYutZ5xhf0hNsgPKvxp-kSWNKM6EYiQnn5IROhP9clucnW1fzlBZyl3nfJ5FNF-vV7rzEwD1TgOIm0Ul0NmLdu=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1ERoa5w7XPuRO7odoDQlFs3PVabDYhmb5j1hMWQvfrm9EjzeRnGrPcI7MSovsj6J4jhwOpvOO-CJ11ANBACBtVBhioinRvDvCw8lYyNY2c9ssX6fLVQvvLZM-WeFZC-M41CB_xRL_4D5aV=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn39mBvP8MZSn4Ll3pd4E8hU9MoEZKUUKJu02zMn6VsEI5-pD1yKuw-7MXyZoS_3BP1xBI350jCSU14UCtXWhvtxIBHDA9tM3H1ENrNEaXaym8ZELS4IMuKsaBhaDSrtsM6N73cFRaZe7Hth=k-no"], "When": "2025-8-10"}]'::jsonb, '{"Friday": {"10": 90, "11": 87, "12": 81, "13": 78, "14": 81, "15": 83, "16": 82, "17": 77, "18": 67, "19": 56, "20": 42, "21": 31, "4": 0, "5": 14, "6": 27, "7": 44, "8": 66, "9": 81}, "Monday": {"10": 81, "11": 70, "12": 59, "13": 61, "14": 67, "15": 80, "16": 82, "17": 82, "18": 74, "19": 64, "20": 51, "21": 35, "4": 0, "5": 12, "6": 24, "7": 43, "8": 65, "9": 80}, "Saturday": {"10": 62, "11": 56, "12": 51, "13": 54, "14": 66, "15": 81, "16": 85, "17": 71, "18": 51, "19": 31, "20": 19, "21": 12, "4": 0, "5": 18, "6": 28, "7": 43, "8": 56, "9": 64}, "Sunday": {"10": 50, "11": 47, "12": 44, "13": 46, "14": 55, "15": 66, "16": 72, "17": 63, "18": 48, "19": 30, "20": 20, "21": 18, "4": 0, "5": 12, "6": 20, "7": 27, "8": 37, "9": 45}, "Thursday": {"10": 81, "11": 77, "12": 67, "13": 65, "14": 74, "15": 89, "16": 99, "17": 100, "18": 92, "19": 84, "20": 69, "21": 51, "4": 0, "5": 16, "6": 25, "7": 40, "8": 60, "9": 76}, "Tuesday": {"10": 90, "11": 89, "12": 86, "13": 87, "14": 93, "15": 94, "16": 95, "17": 90, "18": 86, "19": 82, "20": 63, "21": 44, "4": 0, "5": 21, "6": 29, "7": 41, "8": 61, "9": 78}, "Wednesday": {"10": 87, "11": 79, "12": 71, "13": 70, "14": 77, "15": 82, "16": 85, "17": 79, "18": 70, "19": 62, "20": 51, "21": 41, "4": 0, "5": 13, "6": 24, "7": 46, "8": 71, "9": 86}}'::jsonb, '[{"id": "accessibility", "name": "Accessibility", "options": [{"name": "Wheelchair-accessible entrance", "enabled": true}, {"name": "Wheelchair-accessible parking lot", "enabled": true}]}, {"id": "amenities", "name": "Amenities", "options": [{"name": "Washroom", "enabled": true}]}]'::jsonb, ARRAY['Washroom', 'Wheelchair-accessible entrance', 'Wheelchair-accessible parking lot', 'Athletic club'], NULL, '05:00', '22:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCL